import{_ as a,o as r,c as o,ag as l}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"Part 4 — 売上とレポート（超詳細版）","description":"","frontmatter":{"title":"Part 4 — 売上とレポート（超詳細版）","audience":"オーナー / 店長","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"operations/part4-reports.md","filePath":"operations/part4-reports.md"}'),e={name:"operations/part4-reports.md"};function d(i,t,h,n,s,b){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="part-4-—-売上とレポート" tabindex="-1">Part 4 — 売上とレポート <a class="header-anchor" href="#part-4-—-売上とレポート" aria-label="Permalink to &quot;Part 4 — 売上とレポート&quot;">​</a></h1><p>このページでは、お店の売上・品目別ランキング・スタッフ評価・顧客分析などの各種レポートの見方と活用方法を説明します。</p><div class="tip custom-block"><p class="custom-block-title">レポートの種類と見る画面</p><p>レポートは以下の 2 つの画面に分かれています。</p><ul><li><strong>dashboard.html の「レポート」タブ</strong>（manager 以上）: 基本レポート全般</li><li><strong>owner-dashboard.html のタブ</strong>（owner 専用）: ABC 分析、クロス店舗レポート</li></ul></div><hr><h2 id="_4-1-日次売上の見方" tabindex="-1">4-1. 日次売上の見方 <a class="header-anchor" href="#_4-1-日次売上の見方" aria-label="Permalink to &quot;4-1. 日次売上の見方&quot;">​</a></h2><h3 id="_4-1-1-売上レポートを開く" tabindex="-1">4-1-1. 売上レポートを開く <a class="header-anchor" href="#_4-1-1-売上レポートを開く" aria-label="Permalink to &quot;4-1-1. 売上レポートを開く&quot;">​</a></h3><ol><li>dashboard.html にマネージャー以上でログイン</li><li>上部タブ <strong>【レポート】</strong> → サブタブ <strong>【売上レポート】</strong>（<code>data-tab=&quot;sales&quot;</code>）</li><li>画面が開く</li></ol><h3 id="_4-1-2-表示される項目" tabindex="-1">4-1-2. 表示される項目 <a class="header-anchor" href="#_4-1-2-表示される項目" aria-label="Permalink to &quot;4-1-2. 表示される項目&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>売上合計</td><td>期間内の税込売上合計</td></tr><tr><td>注文件数</td><td>注文数</td></tr><tr><td>客単価</td><td>売上合計 ÷ 注文件数</td></tr><tr><td>時間帯別売上</td><td>1時間ごとの売上推移（棒グラフ）</td></tr><tr><td>日別売上推移</td><td>過去 7 / 30 / 90 日の折れ線グラフ</td></tr><tr><td>支払方法別</td><td>現金・カード・QR の内訳（円グラフ）</td></tr></tbody></table><h3 id="_4-1-3-期間選択" tabindex="-1">4-1-3. 期間選択 <a class="header-anchor" href="#_4-1-3-期間選択" aria-label="Permalink to &quot;4-1-3. 期間選択&quot;">​</a></h3><p>画面上部に期間切替ボタン:</p><ul><li><strong>日次</strong>: 本日の売上</li><li><strong>週次</strong>: 今週月〜日</li><li><strong>月次</strong>: 今月</li><li><strong>カスタム</strong>: 任意の開始日〜終了日</li></ul><h3 id="_4-1-4-活用例" tabindex="-1">4-1-4. 活用例 <a class="header-anchor" href="#_4-1-4-活用例" aria-label="Permalink to &quot;4-1-4. 活用例&quot;">​</a></h3><ul><li>毎朝「昨日の売上」確認</li><li>週次ミーティングで「先週の合計」報告</li><li>月次決算で「月間売上」集計</li><li>同じ曜日の比較（例: 先週金曜と今週金曜）</li></ul><hr><h2 id="_4-2-商品別ランキング" tabindex="-1">4-2. 商品別ランキング <a class="header-anchor" href="#_4-2-商品別ランキング" aria-label="Permalink to &quot;4-2. 商品別ランキング&quot;">​</a></h2><h3 id="_4-2-1-見方" tabindex="-1">4-2-1. 見方 <a class="header-anchor" href="#_4-2-1-見方" aria-label="Permalink to &quot;4-2-1. 見方&quot;">​</a></h3><ol><li>【売上レポート】 内の <strong>「商品別ランキング」</strong> セクション（同じタブ内の下スクロール）</li><li>売上順に品目が表示</li><li>各品目の情報:</li></ol><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>商品名</td><td>メニュー名</td></tr><tr><td>販売数</td><td>期間内の注文数</td></tr><tr><td>売上合計</td><td>円単位</td></tr><tr><td>粗利</td><td>売上 − 原価（レシピ設定時のみ表示）</td></tr></tbody></table><h3 id="_4-2-2-活用例" tabindex="-1">4-2-2. 活用例 <a class="header-anchor" href="#_4-2-2-活用例" aria-label="Permalink to &quot;4-2-2. 活用例&quot;">​</a></h3><ul><li><strong>上位 10 品</strong>: 看板メニューの把握、在庫発注優先度</li><li><strong>下位 10 品</strong>: 廃止候補・値引き候補</li><li><strong>粗利率ランキング</strong>: 利益率の高い品目を積極プッシュ</li></ul><hr><h2 id="_4-3-abc-分析-オーナー専用" tabindex="-1">4-3. ABC 分析（オーナー専用） <a class="header-anchor" href="#_4-3-abc-分析-オーナー専用" aria-label="Permalink to &quot;4-3. ABC 分析（オーナー専用）&quot;">​</a></h2><p>ABC 分析は <strong>owner-dashboard の専用タブ</strong> に移動済み（<code>dashboard.html</code> L92 コメント参照）。manager・staff には表示されません。</p><h3 id="_4-3-1-開く手順" tabindex="-1">4-3-1. 開く手順 <a class="header-anchor" href="#_4-3-1-開く手順" aria-label="Permalink to &quot;4-3-1. 開く手順&quot;">​</a></h3><ol><li>owner アカウントで <code>https://eat.posla.jp/public/admin/owner-dashboard.html</code> を開く</li><li>上部タブ <strong>【ABC 分析】</strong>（<code>data-tab=&quot;abc-analytics&quot;</code>、<code>owner-dashboard.html</code> L52）</li></ol><h3 id="_4-3-2-a-b-c-の定義" tabindex="-1">4-3-2. A / B / C の定義 <a class="header-anchor" href="#_4-3-2-a-b-c-の定義" aria-label="Permalink to &quot;4-3-2. A / B / C の定義&quot;">​</a></h3><p>売上累積シェアで 3 ランクに分類:</p><table tabindex="0"><thead><tr><th>ランク</th><th>シェア</th><th>意味</th><th>対応方針</th></tr></thead><tbody><tr><td><strong>A ランク</strong></td><td>売上上位 70%</td><td>主力商品</td><td><strong>品切れ厳禁</strong>、メイン訴求に使う</td></tr><tr><td><strong>B ランク</strong></td><td>70〜90%</td><td>安定商品</td><td>現状維持、プラスアルファの訴求</td></tr><tr><td><strong>C ランク</strong></td><td>90〜100%</td><td>下位商品</td><td><strong>廃止候補</strong> / メニュー見直し / 値下げ検討</td></tr></tbody></table><h3 id="_4-3-3-活用例" tabindex="-1">4-3-3. 活用例 <a class="header-anchor" href="#_4-3-3-活用例" aria-label="Permalink to &quot;4-3-3. 活用例&quot;">​</a></h3><ul><li>全 50 品のうち C ランク 25 品を見直し</li><li>A ランクの原材料を優先発注</li><li>A ランクの新規バリエーション開発（例: 「醤油ラーメン」が A → 「辛味噌ラーメン」を追加）</li></ul><hr><h2 id="_4-4-バスケット分析-併売分析" tabindex="-1">4-4. バスケット分析（併売分析） <a class="header-anchor" href="#_4-4-バスケット分析-併売分析" aria-label="Permalink to &quot;4-4. バスケット分析（併売分析）&quot;">​</a></h2><p>「○○を注文した人は △△ も買う」傾向を分析。</p><h3 id="_4-4-1-見方" tabindex="-1">4-4-1. 見方 <a class="header-anchor" href="#_4-4-1-見方" aria-label="Permalink to &quot;4-4-1. 見方&quot;">​</a></h3><ol><li>dashboard.html → 【レポート】 → サブタブ <strong>【併売分析】</strong>（<code>data-tab=&quot;basket&quot;</code>、manager 以上）</li><li>品目の組み合わせがリフト値順に表示</li></ol><h3 id="_4-4-2-リフト値とは" tabindex="-1">4-4-2. リフト値とは <a class="header-anchor" href="#_4-4-2-リフト値とは" aria-label="Permalink to &quot;4-4-2. リフト値とは&quot;">​</a></h3><p>「Aを買った人がBも買う確率 ÷ 全注文でBが買われる確率」</p><ul><li>リフト値 &gt; 1: 一緒に買われやすい</li><li>リフト値 = 1: 関係なし（独立）</li><li>リフト値 &lt; 1: むしろ一緒には買われにくい</li></ul><p>例: <strong>ラーメン + 餃子</strong> のリフト値 = 2.5 → ラーメンを食べる人は通常の 2.5 倍の確率で餃子も頼む</p><h3 id="_4-4-3-活用例" tabindex="-1">4-4-3. 活用例 <a class="header-anchor" href="#_4-4-3-活用例" aria-label="Permalink to &quot;4-4-3. 活用例&quot;">​</a></h3><ul><li><strong>セットメニュー提案</strong>: 「ラーメン + 餃子」セットを作って単価アップ</li><li><strong>レコメンド</strong>: セルフメニューで「一緒にいかがですか？」で餃子を推薦</li><li><strong>メニュー配置</strong>: 一緒に頼まれる品目を隣接ページに配置</li></ul><hr><h2 id="_4-5-回転率・客層レポート" tabindex="-1">4-5. 回転率・客層レポート <a class="header-anchor" href="#_4-5-回転率・客層レポート" aria-label="Permalink to &quot;4-5. 回転率・客層レポート&quot;">​</a></h2><h3 id="_4-5-1-開く手順" tabindex="-1">4-5-1. 開く手順 <a class="header-anchor" href="#_4-5-1-開く手順" aria-label="Permalink to &quot;4-5-1. 開く手順&quot;">​</a></h3><ol><li>dashboard.html → 【レポート】 → サブタブ <strong>【回転率・客層】</strong>（<code>data-tab=&quot;turnover&quot;</code>、manager 以上）</li></ol><h3 id="_4-5-2-表示される指標" tabindex="-1">4-5-2. 表示される指標 <a class="header-anchor" href="#_4-5-2-表示される指標" aria-label="Permalink to &quot;4-5-2. 表示される指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th><th>活用</th></tr></thead><tbody><tr><td>平均滞在時間</td><td>着席から会計までの時間（分）</td><td>15 分以下なら回転率高い、90 分以上ならゆっくり利用</td></tr><tr><td>1 日の回転数</td><td>1 テーブルあたり何回お客様が入れ替わったか</td><td>高いほど効率的、低いなら滞在時間長い客が多い</td></tr><tr><td>時間帯別回転傾向</td><td>時間帯ごとの客数推移</td><td>ピーク時間の把握、ラストオーダーの最適化</td></tr><tr><td>曜日別傾向</td><td>月〜日の平均客数</td><td>シフト配置の最適化</td></tr></tbody></table><hr><h2 id="_4-6-スタッフ評価レポート" tabindex="-1">4-6. スタッフ評価レポート <a class="header-anchor" href="#_4-6-スタッフ評価レポート" aria-label="Permalink to &quot;4-6. スタッフ評価レポート&quot;">​</a></h2><h3 id="_4-6-1-開く手順" tabindex="-1">4-6-1. 開く手順 <a class="header-anchor" href="#_4-6-1-開く手順" aria-label="Permalink to &quot;4-6-1. 開く手順&quot;">​</a></h3><ol><li>dashboard.html → 【レポート】 → サブタブ <strong>【スタッフ評価】</strong>（<code>data-tab=&quot;staff-report&quot;</code>、manager 以上）</li></ol><h3 id="_4-6-2-スタッフごとに表示" tabindex="-1">4-6-2. スタッフごとに表示 <a class="header-anchor" href="#_4-6-2-スタッフごとに表示" aria-label="Permalink to &quot;4-6-2. スタッフごとに表示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>スタッフ名</td><td>登録されている <code>display_name</code></td></tr><tr><td>注文入力件数</td><td>ハンディで取った注文数</td></tr><tr><td>売上貢献</td><td>担当した注文の金額合計</td></tr><tr><td>客単価</td><td>担当注文の客単価</td></tr><tr><td>満足度評価</td><td>お客様からの星評価平均（5 段階）</td></tr><tr><td>勤務日数</td><td>期間内の出勤日数</td></tr></tbody></table><h3 id="_4-6-3-活用例" tabindex="-1">4-6-3. 活用例 <a class="header-anchor" href="#_4-6-3-活用例" aria-label="Permalink to &quot;4-6-3. 活用例&quot;">​</a></h3><ul><li><strong>月次評価・ボーナス査定</strong>: 数値ベースで公平に評価</li><li><strong>研修対象の発見</strong>: 客単価が低いスタッフは接客改善研修</li><li><strong>優秀スタッフの昇格判断</strong>: 全指標が高いスタッフはマネージャー候補</li></ul><hr><h2 id="_4-7-予約レポート-l-9" tabindex="-1">4-7. 予約レポート（L-9） <a class="header-anchor" href="#_4-7-予約レポート-l-9" aria-label="Permalink to &quot;4-7. 予約レポート（L-9）&quot;">​</a></h2><h3 id="_4-7-1-開く手順" tabindex="-1">4-7-1. 開く手順 <a class="header-anchor" href="#_4-7-1-開く手順" aria-label="Permalink to &quot;4-7-1. 開く手順&quot;">​</a></h3><ol><li>dashboard.html → 上部タブ <strong>【予約管理】</strong> → サブタブの予約台帳内に統計セクション</li><li>または API: <code>/api/store/reservation-stats.php</code> を運営側で叩く</li></ol><h3 id="_4-7-2-指標" tabindex="-1">4-7-2. 指標 <a class="header-anchor" href="#_4-7-2-指標" aria-label="Permalink to &quot;4-7-2. 指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>予約総数</td><td>期間内の予約数</td></tr><tr><td>来店人数</td><td>実際に来店した予約の人数合計</td></tr><tr><td>no-show 率</td><td>来店しなかった予約の割合</td></tr><tr><td>キャンセル率</td><td>キャンセルされた予約の割合</td></tr><tr><td>ソース別</td><td>web / 電話 / walk-in / AI の内訳</td></tr><tr><td>日別・時間帯別・曜日別</td><td>需要予測に活用</td></tr></tbody></table><hr><h2 id="_4-8-クロス店舗レポート-オーナー向け" tabindex="-1">4-8. クロス店舗レポート（オーナー向け） <a class="header-anchor" href="#_4-8-クロス店舗レポート-オーナー向け" aria-label="Permalink to &quot;4-8. クロス店舗レポート（オーナー向け）&quot;">​</a></h2><p>複数店舗の売上・客数・業績を横並びで比較。</p><h3 id="_4-8-1-開く手順" tabindex="-1">4-8-1. 開く手順 <a class="header-anchor" href="#_4-8-1-開く手順" aria-label="Permalink to &quot;4-8-1. 開く手順&quot;">​</a></h3><ol><li>owner アカウントで owner-dashboard</li><li>上部タブ <strong>【クロス店舗レポート】</strong>（<code>data-tab=&quot;cross-store&quot;</code>、<code>owner-dashboard.html</code> L51）</li></ol><h3 id="_4-8-2-表示項目" tabindex="-1">4-8-2. 表示項目 <a class="header-anchor" href="#_4-8-2-表示項目" aria-label="Permalink to &quot;4-8-2. 表示項目&quot;">​</a></h3><ul><li>店舗ごとの売上合計</li><li>店舗ごとの客数</li><li>店舗ごとの客単価</li><li>全店平均・最大・最小のベンチマーク</li><li>期間別（日次・週次・月次）</li></ul><h3 id="_4-8-3-活用例" tabindex="-1">4-8-3. 活用例 <a class="header-anchor" href="#_4-8-3-活用例" aria-label="Permalink to &quot;4-8-3. 活用例&quot;">​</a></h3><ul><li>全 3 店舗のうち 1 店舗だけ売上低い → 原因調査（立地 / スタッフ / メニュー）</li><li>業績トップ店舗の成功要因を他店舗に横展開</li></ul><hr><h2 id="_4-9-レジ分析-レジ締め精算レポート" tabindex="-1">4-9. レジ分析（レジ締め精算レポート） <a class="header-anchor" href="#_4-9-レジ分析-レジ締め精算レポート" aria-label="Permalink to &quot;4-9. レジ分析（レジ締め精算レポート）&quot;">​</a></h2><h3 id="_4-9-1-開く手順" tabindex="-1">4-9-1. 開く手順 <a class="header-anchor" href="#_4-9-1-開く手順" aria-label="Permalink to &quot;4-9-1. 開く手順&quot;">​</a></h3><ol><li>dashboard.html → 【レポート】 → サブタブ <strong>【レジ分析】</strong>（<code>data-tab=&quot;register&quot;</code>、manager 以上）</li></ol><h3 id="_4-9-2-表示項目" tabindex="-1">4-9-2. 表示項目 <a class="header-anchor" href="#_4-9-2-表示項目" aria-label="Permalink to &quot;4-9-2. 表示項目&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>レジ開閉履歴</td><td>いつ・誰が開けた / 閉めたか</td></tr><tr><td>日別キャッシュログ</td><td>入金・出金・過不足の履歴</td></tr><tr><td>予想在高 vs 実際</td><td>差額がプラスなら過多、マイナスなら不足</td></tr><tr><td>過不足アラート</td><td>閾値（デフォルト ¥500）を超える差額は警告</td></tr></tbody></table><h3 id="_4-9-3-活用例" tabindex="-1">4-9-3. 活用例 <a class="header-anchor" href="#_4-9-3-活用例" aria-label="Permalink to &quot;4-9-3. 活用例&quot;">​</a></h3><ul><li>毎日のレジ締めで過不足チェック</li><li>過不足が続くスタッフの現金取扱い研修</li><li>入金・出金記録漏れのチェック</li></ul><hr><h2 id="_4-10-注文履歴" tabindex="-1">4-10. 注文履歴 <a class="header-anchor" href="#_4-10-注文履歴" aria-label="Permalink to &quot;4-10. 注文履歴&quot;">​</a></h2><h3 id="_4-10-1-開く手順" tabindex="-1">4-10-1. 開く手順 <a class="header-anchor" href="#_4-10-1-開く手順" aria-label="Permalink to &quot;4-10-1. 開く手順&quot;">​</a></h3><ol><li>dashboard.html → 【レポート】 → サブタブ <strong>【注文履歴】</strong>（<code>data-tab=&quot;orders&quot;</code>、manager 以上）</li></ol><h3 id="_4-10-2-表示項目" tabindex="-1">4-10-2. 表示項目 <a class="header-anchor" href="#_4-10-2-表示項目" aria-label="Permalink to &quot;4-10-2. 表示項目&quot;">​</a></h3><ul><li>全注文の一覧（日時・テーブル・品目・金額・ステータス）</li><li>検索フィルタ（日時・テーブル・品目・ステータス）</li><li>CSV エクスポート可</li></ul><h3 id="_4-10-3-活用例" tabindex="-1">4-10-3. 活用例 <a class="header-anchor" href="#_4-10-3-活用例" aria-label="Permalink to &quot;4-10-3. 活用例&quot;">​</a></h3><ul><li>「先週金曜の 19 時の注文を確認したい」等の個別調査</li><li>クレーム対応: お客様から「○○を頼んだはず」と言われた時の確認</li><li>税務監査対応: 過去の取引記録</li></ul><hr><h2 id="_4-11-csv-エクスポートの方法" tabindex="-1">4-11. CSV エクスポートの方法 <a class="header-anchor" href="#_4-11-csv-エクスポートの方法" aria-label="Permalink to &quot;4-11. CSV エクスポートの方法&quot;">​</a></h2><p>各レポートの <strong>【CSV 出力】</strong> ボタンから:</p><ol><li>期間を選択</li><li><strong>【CSV ダウンロード】</strong></li><li>ダウンロードフォルダに保存</li><li>Excel / Numbers / Google Sheets で開く</li></ol><h3 id="文字化け対処" tabindex="-1">文字化け対処 <a class="header-anchor" href="#文字化け対処" aria-label="Permalink to &quot;文字化け対処&quot;">​</a></h3><ul><li>Excel の場合: 「データ」→「テキストから」でインポート時に UTF-8 指定</li><li>Numbers / Google Sheets: デフォルト UTF-8 で OK</li></ul><hr><h2 id="_4-12-活用ストーリー例" tabindex="-1">4-12. 活用ストーリー例 <a class="header-anchor" href="#_4-12-活用ストーリー例" aria-label="Permalink to &quot;4-12. 活用ストーリー例&quot;">​</a></h2><h3 id="例-1-月次決算-毎月-1-日の作業" tabindex="-1">例 1: 月次決算（毎月 1 日の作業） <a class="header-anchor" href="#例-1-月次決算-毎月-1-日の作業" aria-label="Permalink to &quot;例 1: 月次決算（毎月 1 日の作業）&quot;">​</a></h3><ol><li>先月の <strong>売上レポート（月次）</strong> で合計売上を確認</li><li><strong>ABC 分析</strong> で主力商品の推移を見る</li><li><strong>スタッフ評価</strong> で最優秀スタッフにボーナス</li><li><strong>レジ分析</strong> で過不足合計を確認</li></ol><h3 id="例-2-新メニュー導入判断-週次" tabindex="-1">例 2: 新メニュー導入判断（週次） <a class="header-anchor" href="#例-2-新メニュー導入判断-週次" aria-label="Permalink to &quot;例 2: 新メニュー導入判断（週次）&quot;">​</a></h3><ol><li><strong>バスケット分析</strong> で既存メニューの組み合わせ傾向を把握</li><li><strong>ABC 分析</strong> で C ランク品目を特定</li><li>C ランク廃止 → 新メニュー追加の判断</li></ol><h3 id="例-3-スタッフ配置の最適化-月-1-回" tabindex="-1">例 3: スタッフ配置の最適化（月 1 回） <a class="header-anchor" href="#例-3-スタッフ配置の最適化-月-1-回" aria-label="Permalink to &quot;例 3: スタッフ配置の最適化（月 1 回）&quot;">​</a></h3><ol><li><strong>回転率レポート</strong> の時間帯別で、ピーク時間を特定</li><li><strong>スタッフ評価</strong> で客単価の高いスタッフを把握</li><li>ピーク時間に優秀スタッフを配置</li></ol><hr><h2 id="_4-13-よくある質問" tabindex="-1">4-13. よくある質問 <a class="header-anchor" href="#_4-13-よくある質問" aria-label="Permalink to &quot;4-13. よくある質問&quot;">​</a></h2><p><strong>Q1. レポートの数字が合わない</strong></p><p>A1. 期間指定のミスが多い。「営業日区切り時刻」（デフォルト 05:00）を確認。深夜 1 時の売上が「翌日」扱いになっていないか。</p><p><strong>Q2. 粗利が表示されない</strong></p><p>A2. 粗利表示には <strong>レシピ設定</strong>（品目と原材料の紐付け）が必要。在庫・レシピ管理タブで設定してください。</p><p><strong>Q3. スタッフ評価の「担当注文」とは？</strong></p><p>A3. <code>orders.staff_id</code> に記録されたユーザーの注文。ハンディで注文入力した個人スタッフ、または POSレジで会計担当に指定されたスタッフ。</p><p><strong>Q4. ABC 分析が見えない</strong></p><p>A4. ABC 分析は <strong>owner 専用</strong>（manager / staff には非表示）。オーナーアカウントで owner-dashboard にログインしてください。</p><p><strong>Q5. CSV ダウンロードしたら改行がおかしい</strong></p><p>A5. Windows の改行コード問題。Notepad++ 等で「LF」に変換するか、Excel で直接「データ→テキストから」を使用してください。</p><hr><h2 id="_4-14-詳細は" tabindex="-1">4-14. 詳細は <a class="header-anchor" href="#_4-14-詳細は" aria-label="Permalink to &quot;4-14. 詳細は&quot;">​</a></h2><p>→ <a href="./../tenant/13-reports.html">13 章 レポート</a>（フル粒度版）</p><hr><h2 id="_4-15-次のページへ" tabindex="-1">4-15. 次のページへ <a class="header-anchor" href="#_4-15-次のページへ" aria-label="Permalink to &quot;4-15. 次のページへ&quot;">​</a></h2><p>→ <a href="./part5-reservations.html">Part 5: 予約管理</a></p>',119)])])}const g=a(e,[["render",d]]);export{u as __pageData,g as default};
